            <div>
                <?php
                $page_query = new WP_Query('pagename=angebot');
                while ($page_query->have_posts()):
                    $page_query->the_post();
                    ?>

                    <div class='container'>
                        <?php the_title('<h1>', '</h1>'); ?>
                        <?php the_content(); ?>
                    </div>

                <?php endwhile;
                wp_reset_postdata();
                ?>

                <?php
                $angebot_query = new WP_Query(array(
                    'category_name' => 'angebot',
                    'posts_per_page' => -1
                ));

            // ✅ Array mit den SVG-Section IDs
            $svg_sections = array('face', 'body', 'legs', 'hand-feet');
            $section_index = 0;
            
            if ($angebot_query->have_posts()):
                while ($angebot_query->have_posts()):
                    $angebot_query->the_post();
                    
                    // ✅ Hole die aktuelle SVG-Section ID
                    $svg_section_id = isset($svg_sections[$section_index]) ? $svg_sections[$section_index] : '';
                    ?>
                    
                    <!-- ✅ Neu: data-svg-section Attribute -->
                    <article
                        class='angebot-item'
                        data-title='<?php echo esc_attr(get_the_title()); ?>'
                        data-svg-section='<?php echo esc_attr($svg_section_id); ?>'
                        style='display: none;'
                    >                                
                        <?php the_title('<h3>', '</h3>'); ?>
                        <?php the_content(); ?> 
                    </article>
                    
                    <?php
                    $section_index++; // Nächste SVG-Section
                endwhile;
            endif;
            wp_reset_postdata();
            ?>
        </div>
        </div>
            <section id='product-line'>
            <div class='container'>
                <?php
                $product_line_query = new WP_Query(array(
                    'category_name' => 'product-line',
                    'posts_per_page' => 1
                ));
                $product_line_post_id = null;
                
                if ($product_line_query->have_posts()):
                    while ($product_line_query->have_posts()):
                        $product_line_query->the_post();
                        $product_line_post_id = get_the_ID();
                        ?>
                        <article class='product-line-item'>
                            <?php the_title('<h2>', '</h2>'); ?>
                            <?php echo strip_tags(get_the_content(), '<p>'); ?>
                        </article>
                    <?php endwhile;
                endif;
                wp_reset_postdata();
                ?>
            </div>
        </section>
        <!-- Loop-Container Product Line  -->
        <section id='image-loop'>
        <div class='image-loop-container'>
            <div class='image-loop-track'>
                <?php
                if ($product_line_post_id):
                    $images = get_posts(array(
                        'post_type' => 'attachment',
                        'posts_per_page' => -1,
                        'post_parent' => $product_line_post_id,
                        'orderby' => 'menu_order',
                        'order' => 'ASC'
                    ));
                    
                    if ($images):
                        foreach ($images as $image):
                            echo wp_get_attachment_image($image->ID, 'full', false, array('class' => 'loop-image'));
                        endforeach;
                    endif;
                endif;
                ?>
            </div>
        </div>
    </section>
